        <StatCard 
          label="Pending Orders" 
          value="14" 
          icon={<TrendingUp className="text-indigo-600" />} 
          trend="8 new"
        />
        <StatCard 
          label="Low Stock Alerts" 
          value={lowStockItems.length.toString()} 
          icon={<AlertTriangle className="text-amber-600" />} 
          trend="Action required"
