      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl tally-shadow">
          <h3 className="text-lg font-semibold mb-6">Production vs Sales</h3>
