export default Dashboard;

import React, { useState } from 'react';
import { Send, Bot, User, Sparkles } from 'lucide-react';
import { getERPInsights } from '../services/geminiService';

interface AIAssistantProps {
  erpData: any;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ erpData }) => {
  const [query, setQuery] = useState('');
  const [messages, setMessages] = useState<{role: 'user' | 'bot', text: string}[]>([
    { role: 'bot', text: "Hello! I'm your ForgeERP Intelligence agent. Ask me about stock levels, production feasibility, or financial summaries." }
  ]);
  const [isLoading, setIsLoading] = useState(false);

  const handleSend = async () => {
    if (!query.trim()) return;

    const userMsg = query;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setQuery('');
    setIsLoading(true);

    const botResponse = await getERPInsights(erpData, userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse || 'I am sorry, I am unable to process that.' }]);
    setIsLoading(false);
  };

  return (
    <div className="h-[calc(100vh-10rem)] flex flex-col bg-white rounded-2xl tally-shadow overflow-hidden border border-slate-100">
      <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-100 rounded-xl flex items-center justify-center">
            <Bot className="text-indigo-600" />
          </div>
          <div>
            <h3 className="font-bold text-slate-800">AI Plant Consultant</h3>
            <p className="text-xs text-green-600 font-semibold flex items-center gap-1">
              <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
              Powered by Gemini
            </p>
          </div>
        </div>
        <div className="hidden sm:flex gap-2">
           <button onClick={() => setQuery("Give me a stock summary")} className="text-xs px-3 py-1.5 bg-slate-100 hover:bg-slate-200 rounded-full text-slate-600 transition-all">Stock Summary</button>
           <button onClick={() => setQuery("Check production bottleneck")} className="text-xs px-3 py-1.5 bg-slate-100 hover:bg-slate-200 rounded-full text-slate-600 transition-all">Bottlenecks</button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
            <div className={`flex gap-3 max-w-[80%] ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
              <div className={`w-8 h-8 rounded-lg flex items-center justify-center shrink-0 ${msg.role === 'user' ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                {msg.role === 'user' ? <User size={16} className="text-white" /> : <Bot size={16} className="text-slate-600" />}
              </div>
              <div className={`p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-slate-50 text-slate-700 border border-slate-100 rounded-tl-none'}`}>
                {msg.text}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="flex gap-3 items-center">
              <div className="w-8 h-8 rounded-lg bg-slate-200 flex items-center justify-center">
                <Bot size={16} className="text-slate-600" />
              </div>
              <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce delay-100"></div>
                <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce delay-200"></div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 bg-slate-50/50 border-t border-slate-100">
        <div className="relative">
          <input 
            type="text" 
            placeholder="Ask anything about your manufacturing data..."
            className="w-full bg-white border border-slate-200 rounded-2xl py-4 pl-6 pr-14 focus:ring-2 focus:ring-indigo-500 focus:outline-none shadow-sm transition-all"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          />
          <button 
            onClick={handleSend}
            disabled={isLoading || !query.trim()}
            className="absolute right-3 top-2.5 p-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-lg shadow-indigo-600/20"
          >
            <Send size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIAssistant;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './views/Dashboard';
import Accounting from './views/Accounting';
import AIAssistant from './views/AIAssistant';
import { 
  ViewType, 
  Ledger, 
  StockItem, 
  Voucher, 
  VoucherType, 
  BillOfMaterials 
} from './types';
import { 
  INITIAL_LEDGERS, 
  INITIAL_STOCK, 
  INITIAL_BOMS 
} from './constants';
import { Package, Factory, BarChart3, Settings, Bell } from 'lucide-react';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('DASHBOARD');
  const [ledgers, setLedgers] = useState<Ledger[]>(INITIAL_LEDGERS);
  const [inventory, setInventory] = useState<StockItem[]>(INITIAL_STOCK);
  const [boms, setBoms] = useState<BillOfMaterials[]>(INITIAL_BOMS);
  const [vouchers, setVouchers] = useState<Voucher[]>([]);

  const handleAddVoucher = (newV: Omit<Voucher, 'id'>) => {
    const voucher: Voucher = { ...newV, id: `v${Date.now()}` };
    setVouchers([...vouchers, voucher]);

    // Update Ledgers (Basic Tally Double Entry logic)
    setLedgers(prev => prev.map(l => {
      if (l.id === voucher.debitLedgerId) return { ...l, balance: l.balance + voucher.amount };
      if (l.id === voucher.creditLedgerId) return { ...l, balance: l.balance - voucher.amount };
      return l;
    }));
  };

  const renderContent = () => {
    switch (activeView) {
      case 'DASHBOARD':
        return <Dashboard ledgers={ledgers} inventory={inventory} />;
      case 'ACCOUNTING':
        return <Accounting ledgers={ledgers} onAddVoucher={handleAddVoucher} />;
      case 'AI_ASSISTANT':
        return <AIAssistant erpData={{ ledgers, inventory, vouchers, boms }} />;
      case 'INVENTORY':
        return (
          <div className="p-8 bg-white rounded-2xl tally-shadow text-center">
            <Package size={48} className="mx-auto text-slate-300 mb-4" />
            <h3 className="text-xl font-bold">Inventory Management</h3>
            <p className="text-slate-500">Stock details, categorization, and location tracking.</p>
            <div className="mt-8 grid grid-cols-1 md:grid-cols-3 gap-6 text-left">
               {inventory.map(item => (
                 <div key={item.id} className="p-4 border rounded-xl hover:border-indigo-500 transition-colors">
                   <p className="text-xs font-bold text-slate-400 uppercase">{item.category}</p>
                   <h4 className="font-bold text-slate-800">{item.name}</h4>
                   <div className="flex justify-between mt-2">
                     <span className="text-sm text-slate-500">Stock: {item.quantity} {item.unit}</span>
                     <span className="text-sm font-semibold text-indigo-600">${item.rate}/{item.unit}</span>
                   </div>
                 </div>
               ))}
            </div>
          </div>
        );
      case 'MANUFACTURING':
        return (
          <div className="p-8 bg-white rounded-2xl tally-shadow text-center">
            <Factory size={48} className="mx-auto text-slate-300 mb-4" />
            <h3 className="text-xl font-bold">Manufacturing & BOM</h3>
            <p className="text-slate-500">Multi-level Bill of Materials and Production Orders.</p>
            <div className="mt-8 space-y-4 text-left max-w-2xl mx-auto">
              {boms.map(bom => {
                const finishedGood = inventory.find(i => i.id === bom.finishedGoodId);
                return (
                  <div key={bom.id} className="p-6 border rounded-2xl">
                    <h4 className="font-bold text-lg mb-4">Recipe for: {finishedGood?.name}</h4>
                    <div className="space-y-2">
                      {bom.components.map(comp => {
                        const compItem = inventory.find(i => i.id === comp.itemId);
                        return (
                          <div key={comp.itemId} className="flex justify-between items-center text-sm py-2 border-b border-slate-50 last:border-0">
                            <span className="text-slate-600">{compItem?.name}</span>
                            <span className="font-mono bg-slate-50 px-2 py-1 rounded">{comp.quantity} {compItem?.unit}</span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        );
      case 'REPORTS':
        return (
          <div className="p-8 bg-white rounded-2xl tally-shadow text-center">
            <BarChart3 size={48} className="mx-auto text-slate-300 mb-4" />
            <h3 className="text-xl font-bold">Reports & Analysis</h3>
            <p className="text-slate-500">Profit & Loss, Balance Sheet, and Production Efficiency.</p>
          </div>
        );
      default:
        return <Dashboard ledgers={ledgers} inventory={inventory} />;
    }
  };

  return (
    <div className="min-h-screen flex bg-slate-50">
      <Sidebar activeView={activeView} onViewChange={setActiveView} />

      <main className="flex-1 lg:ml-64 p-4 lg:p-8">
        <div className="max-w-7xl mx-auto">
          {/* Top Bar */}
          <header className="flex justify-between items-center mb-8 bg-white p-4 rounded-2xl tally-shadow">
            <div className="flex items-center gap-4">
               <h1 className="text-sm font-bold text-slate-400 uppercase tracking-widest hidden sm:block">ForgeERP Cloud v2.4</h1>
            </div>
            <div className="flex items-center gap-4">
              <button className="p-2.5 text-slate-500 hover:bg-slate-50 rounded-xl transition-all relative">
                <Bell size={20} />
                <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
              </button>
              <button className="p-2.5 text-slate-500 hover:bg-slate-50 rounded-xl transition-all">
                <Settings size={20} />
              </button>
              <div className="h-8 w-[1px] bg-slate-100 mx-2"></div>
              <div className="flex items-center gap-2 px-3 py-1.5 bg-indigo-50 text-indigo-700 rounded-lg">
                <div className="w-2 h-2 bg-indigo-600 rounded-full animate-pulse"></div>
                <span className="text-xs font-bold">LIVE PRODUCTION</span>
              </div>
            </div>
          </header>

          <div className="animate-in fade-in duration-500">
            {renderContent()}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

