                                </div>
                              </td>
                              <td className="px-6 py-4 text-right font-medium text-slate-500">
                                ${item?.rate}
                              </td>
                            </tr>
                          );
                        })}
                      </tbody>
                    </table>
                  </div>

                  <div className="mt-6 flex justify-end gap-3">
